export function clientScript() {
    return `let selected=0;let activeTab='Event Detail';let activeFilter='all';const events=replayData.events||[];function escHtml(s){return String(s??'').replace(/[&<>"']/g,function(m){return {'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[m]})}function limit(v,n=20000){const s=String(v??'');return s.length>n?s.slice(0,n)+'\\n\\nOutput truncated. Open Raw JSON for preserved source metadata.':s}function template(id){return document.getElementById(id).innerHTML}function has(v){return v!==undefined&&v!==null&&String(v).trim()!==''}function statusOf(ev){return ev.type==='error'||(ev.exitCode??0)!==0?'failed':ev.type==='unknown'||(ev.warnings||[]).length?'minor-warning':'completed'}function isIssue(ev){return statusOf(ev)!=='completed'}function visibleIndexes(){return events.map((e,i)=>({e,i})).filter(x=>activeFilter==='all'||isIssue(x.e)).map(x=>x.i)}function firstVisible(){const v=visibleIndexes();return v.length?v[0]:-1}function fmtMs(ms){return ms==null?'':(ms<1000?ms+'ms':(ms/1000).toFixed(ms<10000?2:1)+'s')}function metaRows(rows){const html=rows.filter(r=>has(r[1])&&r[1]!=='Unavailable').map(r=>'<div class="meta-item"><div class="metadata-label">'+escHtml(r[0])+'</div><div class="metadata-value '+(r[2]?'mono':'')+'">'+escHtml(r[1])+'</div></div>').join('');return html?'<div class="metadata-strip"><div class="meta-grid">'+html+'</div></div>':''}function section(title,body,cls=''){return has(body)?'<section class="detail-section '+cls+'"><h4>'+escHtml(title)+'</h4>'+body+'</section>':''}function pre(v){return '<pre>'+escHtml(limit(v))+'</pre>'}function preview(v){if(!has(v))return '';const s=String(v);return '<pre>'+escHtml(limit(s,900))+'</pre>'+(s.length>900?'<details class="raw-metadata"><summary>Full output</summary>'+pre(s)+'</details>':'')}function rawDetails(obj){return '<details class="raw-metadata"><summary>Event metadata</summary><pre>'+escHtml(limit(JSON.stringify(obj,null,2)))+'</pre></details>'}function fmtTok(n){if(typeof n!=='number'||!Number.isFinite(n))return '—';if(Math.abs(n)>=1000000)return (n/1000000).toFixed(n%1000000?1:0)+'m';if(Math.abs(n)>=1000)return (n/1000).toFixed(n%1000?1:0)+'k';return String(n)}function tokenSection(ev){const u=ev.tokenUsage;if(!u)return section('Token usage','<p class="muted">Not captured for this event.</p>','token-usage');const rows=[['Input',u.inputTokens],['Output',u.outputTokens],['Cache read',u.cacheReadTokens],['Cache creation',u.cacheCreationTokens],['Cached',u.cachedTokens],['Reasoning',u.reasoningTokens],['Total',u.totalTokens]].filter(r=>typeof r[1]==='number').map(r=>'<div class="meta-item"><div class="metadata-label">'+escHtml(r[0])+'</div><div class="metadata-value">'+escHtml(fmtTok(r[1]))+'</div></div>').join('');return section('Token usage','<div class="metadata-strip"><div class="meta-grid">'+rows+'</div></div>','token-usage')}function shell(title,chip,summary,body,meta,raw){return '<div class="detail-event-layout"><div class="detail-hero"><div class="detail-summary"><h3>'+escHtml(title||'Replay event')+'</h3>'+chip+(has(summary)?'<p>'+escHtml(summary)+'</p>':'')+'</div></div>'+body+tokenSection(raw)+meta+rawDetails(raw)+'</div>'}function chip(s){return '<span class="status-chip '+escHtml(s)+'">'+escHtml(s)+'</span>'}function rawContent(ev){if(has(ev.summary))return ev.summary;if(has(ev.raw)&&typeof ev.raw==='object'){const r=ev.raw;return r.content||r.message||r.text||r.prompt||r.output||''}return ''}function relatedPaths(ev){const paths=[];if(has(ev.path))paths.push(ev.path);if(has(ev.diff)){String(ev.diff).split('\\n').forEach(l=>{const m=l.match(/^diff --git a\\/(.+?) b\\//)||l.match(/^[-+]{3} [ab]\\/(.+)$/);if(m)paths.push(m[1])})}return Array.from(new Set(paths)).slice(0,12)}function failedCommand(ev){const paths=relatedPaths(ev);const body=section('Command',pre(ev.command),'primary')+section('Failure summary','<p>'+escHtml(ev.summary||'The captured command exited with a non-zero status.')+'</p>')+section('stdout',preview(ev.stdout))+section('stderr',preview(ev.stderr))+section('Why this matters','<p>The replay was generated successfully, but the captured agent command failed. Investigate this command before trusting the run outcome.</p>')+section('Related file paths',paths.length?'<ul class="path-list">'+paths.map(p=>'<li class="mono">'+escHtml(p)+'</li>').join('')+'</ul>':'');return shell(ev.title||'Command failed',chip('failed'),'',body,metaRows([['Source','Captured agent run'],['Exit code',ev.exitCode],['Working directory',ev.cwd,true],['Start time',ev.raw?.startTime||ev.raw?.start?.timestamp||ev.timestamp],['End time',ev.raw?.endTime||ev.raw?.result?.timestamp],['Duration',fmtMs(ev.durationMs)],['Provider',ev.provider||replayData.provider],['Timestamp',ev.timestamp],['Event ID',ev.id,true]]),ev)}function successfulCommand(ev){const output=ev.stdout||ev.stderr;const body=section('Command',pre(ev.command),'primary')+section('Output preview',preview(output));return shell(ev.title||'Command completed',chip('completed'),ev.summary||'',body,metaRows([['Source','Captured agent run'],['Exit code',ev.exitCode??0],['Duration',fmtMs(ev.durationMs)],['Working directory',ev.cwd,true],['Timestamp',ev.timestamp]]),ev)}function fileEvent(ev){const body=section('File path',has(ev.path)?'<p class="mono">'+escHtml(ev.path)+'</p>':'','primary')+section('Change preview',preview(ev.diff||ev.summary))+section('Related command or tool',has(ev.command)?pre(ev.command):'');const added=has(ev.diff)?(String(ev.diff).match(/^\\+/gm)||[]).length-1:'';const removed=has(ev.diff)?(String(ev.diff).match(/^- /gm)||[]).length:'';return shell(ev.title||'File change',chip(ev.type.replace('_',' ')),ev.summary||'',body,metaRows([['Source','Captured agent run'],['Operation',ev.type],['Added lines',added>0?added:''],['Removed lines',removed>0?removed:''],['Timestamp',ev.timestamp]]),ev)}function messageEvent(ev){const isUser=ev.type==='user_message';const content=rawContent(ev)||ev.title;const body=section(isUser?'User prompt':'Message',pre(content),'primary');return shell(ev.title||(isUser?'User prompt':'Assistant message'),chip(ev.type.replace('_',' ')),isUser?'Captured prompt that initiated or guided the run.':(ev.summary||''),body,metaRows([['Source','Captured agent run'],['Provider',ev.provider||replayData.provider],['Timestamp',ev.timestamp],['Event ID',ev.id,true]]),ev)}function fallbackEvent(ev){const body=section('Summary','<p>'+escHtml(ev.summary||ev.title||'Event captured with limited structured fields.')+'</p>');return shell(ev.title||'Replay event',chip(statusOf(ev)),ev.type||'',body,metaRows([['Source',ev.type==='unknown'?'Recorder pipeline':'Captured agent run'],['Type',ev.type],['Provider',ev.provider||replayData.provider],['Path',ev.path,true],['Command',ev.command,true],['Exit code',ev.exitCode],['Timestamp',ev.timestamp]]),ev)}function eventHtml(ev){if(ev.command&&(ev.type==='error'||(ev.exitCode??0)!==0))return failedCommand(ev);if(ev.command)return successfulCommand(ev);if(ev.type&&ev.type.includes('file'))return fileEvent(ev);if(ev.type==='user_message'||ev.type==='assistant_message'||ev.type.includes('message'))return messageEvent(ev);return fallbackEvent(ev)}function updateFilterUi(){document.querySelectorAll('[data-filter]').forEach(btn=>btn.classList.toggle('active',btn.dataset.filter===activeFilter));document.querySelectorAll('[data-event-index]').forEach(row=>{const idx=Number(row.dataset.eventIndex);row.style.display=activeFilter==='all'||isIssue(events[idx])?'grid':'none'});const visible=visibleIndexes();const title=document.getElementById('timelineTitle');if(title)title.textContent=activeFilter==='warnings'?'Timeline: Issues only':'Replay Event Timeline';const count=document.getElementById('timelineCount');if(count)count.textContent=visible.length+' of '+events.length+' events visible';const empty=document.getElementById('issueEmpty');if(empty)empty.style.display=activeFilter==='warnings'&&visible.length===0?'block':'none';if(!visible.includes(selected)){selected=firstVisible();}document.querySelectorAll('.timeline-row').forEach(r=>r.classList.toggle('selected',Number(r.dataset.eventIndex)===selected));}
function renderDetail(){if(selected<0){document.getElementById('detailContent').innerHTML='<div class="empty-state"><h3>No issue events found in this replay.</h3><p>The issue filter is active, but every captured event is currently clean.</p><button data-filter="all" class="inline-filter-reset">Show all events</button></div>';document.querySelector('.inline-filter-reset')?.addEventListener('click',()=>{activeFilter='all';selected=0;updateFilterUi();renderDetail()});return}const ev=events[selected]||events[0]||{};let html='';if(activeTab==='Event Detail')html=eventHtml(ev);if(activeTab==='Changed Files')html='<pre>'+template('changedFiles')+'</pre>';if(activeTab==='Diff')html='<pre>'+template('gitDiff')+'</pre>';if(activeTab==='Raw JSON')html='<pre>'+escHtml(limit(JSON.stringify(ev,null,2)))+'</pre>';if(activeTab==='Warnings')html='<div class="warning-groups">'+template('warningsData')+'</div>';if(activeTab==='Redaction')html='<div class="redaction-summary">'+template('redactionData')+'</div>';document.getElementById('detailContent').innerHTML=html;const fill=document.getElementById('scrubFill');if(fill){const total=Math.max((events.length||1)-1,1);fill.style.width=Math.round((Math.max(selected,0)/total)*100)+'%'}}function setActiveTab(tab){activeTab=tab;document.querySelectorAll('.tab').forEach(t=>t.classList.toggle('active',t.dataset.tab===activeTab))}document.querySelectorAll('[data-event-index]').forEach(btn=>btn.addEventListener('click',()=>{selected=Number(btn.dataset.eventIndex);setActiveTab('Event Detail');updateFilterUi();renderDetail()}));document.querySelectorAll('.tab').forEach(btn=>btn.addEventListener('click',()=>{setActiveTab(btn.dataset.tab);renderDetail()}));document.querySelectorAll('[data-filter]').forEach(btn=>btn.addEventListener('click',()=>{activeFilter=btn.dataset.filter;setActiveTab('Event Detail');updateFilterUi();renderDetail()}));if(window.matchMedia&&window.matchMedia('(max-width: 700px)').matches){document.querySelectorAll('.diagnostics-details[open]').forEach(d=>{if(!d.classList.contains('has-issue'))d.removeAttribute('open')})}updateFilterUi();renderDetail();`;
}
